document.getElementById("grant-btn").addEventListener("click",async()=>{const e=document.getElementById("status");e.textContent="Requesting...",e.style.color="#666";try{(await navigator.mediaDevices.getUserMedia({audio:!0,video:!1})).getTracks().forEach(e=>e.stop()),e.innerHTML="✅ Permission Granted! You can close this tab and hit 'Start Listening' in your side panel.",e.style.color="green"}catch(t){e.innerHTML=`❌ Error: ${t.message}. Please click the lock/settings icon in the URL bar and allow microphone.`,e.style.color="red"}});